#include <bits/stdc++.h>
using namespace std;
bool a[1000010];
int m[1000010],n,b,ans;
int main(){
    cin>>n>>b;
    a[0]=a[1]=1;
    for(int i=2;i<=n;i++){
        if(a[i]==0){
            m[i]=i;
            for(int j=i*2;j<=n;j+=i){
                a[j]=1;
                m[j]=i;
            }
        }
    }
    for(int i=1;i<=n;i++){
        if(m[i]<=b){
            ans++;
        }
    }
    cout<<ans;
    return 0;
}
